mapper.select:
SELECT WI.WAREHOUSE_ID AS warehouseId, WI.WAREHOUSE_NAME AS warehouseName, MC.ID AS materialId, MC.MATERIAL_NAME AS materialName, CASE WHEN c3.CATEGORY_NAME IS NOT NULL AND c2.CATEGORY_NAME IS NOT NULL AND c.CATEGORY_NAME IS NOT NULL THEN c3.CATEGORY_NAME || '/' || c2.CATEGORY_NAME || '/' || c.CATEGORY_NAME WHEN c2.CATEGORY_NAME IS NOT NULL AND c.CATEGORY_NAME IS NOT NULL THEN c2.CATEGORY_NAME || '/' || c.CATEGORY_NAME WHEN c.CATEGORY_NAME IS NOT NULL THEN c.CATEGORY_NAME ELSE '' END AS categoryName, MC.SPECIFICATION_MODEL AS specificationModel, MC.BRAND AS brand, MC.UNIT_CODE AS unitCode, MC.UNIT_NAME AS unitName, NVL(SUM(WID.REMAINING_QUANTITY), 0) AS stockQuantity, CASE WHEN NVL(SUM(WID.REMAINING_QUANTITY), 0) > 0 THEN NVL(SUM(WID.REMAINING_QUANTITY * NVL(WID.TAX_INCLUDED_UNIT_PRICE, 0)), 0) / NVL(SUM(WID.REMAINING_QUANTITY), 0) ELSE 0 END AS stockUnitPrice, NVL(SUM(WID.REMAINING_QUANTITY * NVL(WID.TAX_INCLUDED_UNIT_PRICE, 0)), 0) AS stockTotalPrice FROM E_MATERIAL_WAREHOUSE_IN_DETAIL WID INNER JOIN E_MATERIAL_WAREHOUSE_IN WI ON WID.WAREHOUSE_IN_ID = WI.ID AND WI.ACCEPTANCE_STATUS = 1 INNER JOIN E_MATERIAL_CODE MC ON WID.MATERIAL_ID = MC.ID AND MC.DEL_FLAG = 0 LEFT JOIN E_MATERIAL_CATEGORY c ON MC.CATEGORY_ID = c.ID AND c.DEL_FLAG = 0 LEFT JOIN E_MATERIAL_CATEGORY c2 ON c.PARENT_ID = c2.ID AND c2.DEL_FLAG = 0 LEFT JOIN E_MATERIAL_CATEGORY c3 ON c2.PARENT_ID = c3.ID AND c3.DEL_FLAG = 0
WID.REMAINING_QUANTITY > 0
AND WI.WAREHOUSE_ID = #{warehouseId}
AND WI.WAREHOUSE_NAME LIKE #{warehouseNamePattern}
AND MC.ID = #{materialId}
AND MC.MATERIAL_NAME LIKE #{materialNamePattern}
AND MC.CATEGORY_ID = #{categoryId}
AND MC.SPECIFICATION_MODEL LIKE #{specificationModelPattern}
AND MC.BRAND LIKE #{brandPattern}
GROUP BY WI.WAREHOUSE_ID, WI.WAREHOUSE_NAME, MC.ID, MC.MATERIAL_NAME, CASE WHEN c3.CATEGORY_NAME IS NOT NULL AND c2.CATEGORY_NAME IS NOT NULL AND c.CATEGORY_NAME IS NOT NULL THEN c3.CATEGORY_NAME || '/' || c2.CATEGORY_NAME || '/' || c.CATEGORY_NAME WHEN c2.CATEGORY_NAME IS NOT NULL AND c.CATEGORY_NAME IS NOT NULL THEN c2.CATEGORY_NAME || '/' || c.CATEGORY_NAME WHEN c.CATEGORY_NAME IS NOT NULL THEN c.CATEGORY_NAME ELSE '' END, MC.SPECIFICATION_MODEL, MC.BRAND, MC.UNIT_CODE, MC.UNIT_NAME ORDER BY WI.WAREHOUSE_NAME, MC.MATERIAL_NAME
